<script>
// import Velocity from "velocity-animate";
import { throttle } from "../utils/utils.js";

let eventHandle = {
  getEvent: function(event) {
    return event || window.event;
  },
  addEvent: function(element, type, handler) {
    if (element.addEventListener) {
      element.addEventListener(type, handler, false);
    } else if (element.attachEvent) {
      element.attachEvent("on" + type, handler);
    } else {
      element["on" + type] = handler;
    }
  },
  getWheelDelta: function(event) {
    return event.wheelDelta ? event.wheelDelta : -event.detail * 40;
  }
};
export default {
  name: "value",
  data() {
    return {
      direction: 0,
      screenIndex: 0,
      prevIndex: 0,
      isAnimating: false,
      unlockTimer: null,
      language: localStorage.Language || "CHS"
    };
  },
  mounted() {
    document.addEventListener("wheel", this.mouseHandle, { passive: false });
    document.addEventListener("DOMMouseScroll", this.mouseHandle, false);
    document.addEventListener("keydown", this.keyHandle);
    window.addEventListener("carousel:navigate", this.handleExternalNavigation);
    this.lockBodyScroll();
    this.emitState();
  },
  beforeDestroy() {
    this.cleanupListeners();
  },
  watch: {
    screenIndex() {
      this.emitState();
    }
  },
  methods: {
    emitState() {
      this.$emit("carousel-state", {
        screenIndex: this.screenIndex,
        isEnd: this.screenIndex === 5,
        isStart: this.screenIndex === 0
      });
    },
    lockBodyScroll() {
      document.body.style.overflow = document.documentElement.style.overflow =
        "hidden";
    },
    cleanupListeners() {
      document.removeEventListener("wheel", this.mouseHandle, false);
      document.removeEventListener("DOMMouseScroll", this.mouseHandle, false);
      document.removeEventListener("keydown", this.keyHandle);
      window.removeEventListener(
        "carousel:navigate",
        this.handleExternalNavigation
      );
      clearTimeout(this.unlockTimer);
    },
    handleExternalNavigation(event) {
      const nextIndex =
        event && event.detail ? Number(event.detail.index) : this.screenIndex;
      this.setScreenIndex(nextIndex);
    },
    pageEnter(page) {
      if (page !== this.screenIndex) {
        return;
      }
      clearTimeout(this.unlockTimer);
      this.unlockTimer = setTimeout(() => {
        this.isAnimating = false;
      }, 250);
    },
    mouseHandle(event) {
      event = eventHandle.getEvent(event);
      if (event.preventDefault) {
        event.preventDefault();
      }
      this.direction = eventHandle.getWheelDelta(event);
      throttle(this.direction < 0 ? this.next : this.prev, this, 80);
    },
    keyHandle(event) {
      if (event.key === "ArrowDown" || event.key === "PageDown") {
        event.preventDefault();
        this.next();
      }
      if (event.key === "ArrowUp" || event.key === "PageUp") {
        event.preventDefault();
        this.prev();
      }
    },
    setScreenIndex(nextIndex) {
      if (
        this.isAnimating ||
        nextIndex < 0 ||
        nextIndex > 5 ||
        nextIndex === this.screenIndex
      ) {
        return;
      }
      this.isAnimating = true;
      this.prevIndex = this.screenIndex;
      this.screenIndex = nextIndex;
      clearTimeout(this.unlockTimer);
      this.unlockTimer = setTimeout(() => {
        this.isAnimating = false;
      }, 1400);
    },
    next() {
      this.setScreenIndex(this.screenIndex + 1);
    },
    prev() {
      this.setScreenIndex(this.screenIndex - 1);
    },
    goBackToVI() {
      this.setScreenIndex(4);
    }
  },
  beforeRouteLeave(to, from, next) {
    this.cleanupListeners();
    document.body.style.overflow = document.documentElement.style.overflow =
      "auto";
    next();
  }
};
</script>
